"use client";

import { useRender } from "@base-ui/react";
import type { StyleXStyles } from "@stylexjs/stylex";

import { cx, x } from "@/lib/utils.stylex";

import { styles } from "./marker.stylex";

type MarkerVariant = "default" | "separator" | "border";
const markerVariants: Record<MarkerVariant, StyleXStyles> = {
  border: styles.border,
  default: null,
  separator: styles.separator,
};

const Marker = ({
  className,
  style,
  variant = "default",
  render,
  ...props
}: React.ComponentProps<"div"> & {
  variant?: MarkerVariant;
  render?: useRender.RenderProp;
}) => {
  const p = x(styles.root, markerVariants[variant]);
  return useRender({
    props: {
      className: cx(p.className, className),
      "data-slot": "marker",
      "data-variant": variant,
      style: { ...p.style, ...style },
      ...props,
    },
    render: render ?? <div />,
  });
};

const MarkerIcon = ({
  className,
  style,
  ...props
}: React.ComponentProps<"span">) => {
  const p = x(styles.icon);
  return (
    <span
      aria-hidden="true"
      className={cx(p.className, className)}
      data-slot="marker-icon"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const MarkerContent = ({
  className,
  style,
  ...props
}: React.ComponentProps<"span">) => {
  const p = x(styles.content);
  return (
    <span
      className={cx(p.className, className)}
      data-slot="marker-content"
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

export { Marker, MarkerIcon, MarkerContent, markerVariants };

import * as stylex from "@stylexjs/stylex";

import { colors } from "@/lib/tokens.stylex";

export const styles = stylex.create({
  border: {
    borderBottom: `1px solid ${colors.border}`,
    paddingBottom: "0.5rem",
  },
  content: { minWidth: 0, overflowWrap: "break-word" },
  icon: { flexShrink: 0, height: "1rem", width: "1rem" },
  root: {
    alignItems: "center",
    color: colors.mutedForeground,
    display: "flex",
    fontSize: "0.875rem",
    gap: "0.5rem",
    minHeight: "1rem",
    position: "relative",
    textAlign: "left",
    width: "100%",
  },
  separator: {
    borderBottom: `1px solid ${colors.border}`,
    borderTop: `1px solid ${colors.border}`,
    justifyContent: "center",
    paddingBlock: "0.5rem",
  },
});
